example.code:
Pattern: {Allow|Deny}{Direction}{Protocol}{Description}
Good names: AllowInboundHTTPS - allow inbound TCP/443 from App Gateway subnet AllowInboundHTTP - allow inbound TCP/80 from App Gateway subnet AllowOutboundSQL - allow outbound TCP/5432 to data subnet AllowAzureLoadBalancer - allow LB health probes (service tag) DenyAllInbound - explicit deny-all catchall at priority 4096
Bad names: rule1 - no semantic content allow-https - no direction MyRule - no direction, no protocol

resource "azurerm_network_security_group" "private" { name = "${var.project}-${var.environment}-private-nsg" location = azurerm_resource_group.main.location resource_group_name = azurerm_resource_group.main.name
# Allow HTTPS from Application Gateway subnet only security_rule { name = "AllowInboundHTTPS" priority = 100 direction = "Inbound" access = "Allow" protocol = "Tcp" source_port_range = "*" destination_port_range = "443" source_address_prefix = "10.0.2.0/24" # App Gateway subnet destination_address_prefix = "*" }
# Allow Azure Load Balancer health probes security_rule { name = "AllowAzureLoadBalancer" priority = 200 direction = "Inbound" access = "Allow" protocol = "*" source_port_range = "*" destination_port_range = "*" source_address_prefix = "AzureLoadBalancer" destination_address_prefix = "*" }
# Explicit deny-all at lowest priority security_rule { name = "DenyAllInbound" priority = 4096 direction = "Inbound" access = "Deny" protocol = "*" source_port_range = "*" destination_port_range = "*" source_address_prefix = "*" destination_address_prefix = "*" }
tags = local.common_tags }
resource "azurerm_subnet_network_security_group_association" "private" { subnet_id = azurerm_subnet.private.id network_security_group_id = azurerm_network_security_group.private.id }

# Web tier: only App Gateway can reach it resource "azurerm_network_security_group" "web" { name = "${var.project}-${var.environment}-web-nsg" location = azurerm_resource_group.spoke.location resource_group_name = azurerm_resource_group.spoke.name
security_rule { name = "AllowAppGatewayHTTPS" priority = 100 direction = "Inbound" access = "Allow" protocol = "Tcp" source_port_range = "*" destination_port_range = "443" source_address_prefix = "10.1.0.0/24" # appgw subnet destination_address_prefix = "*" } security_rule { name = "AllowAzureLoadBalancer" priority = 200 direction = "Inbound" access = "Allow" protocol = "*" source_port_range = "*" destination_port_range = "*" source_address_prefix = "AzureLoadBalancer" destination_address_prefix = "*" } security_rule { name = "DenyAllInbound" priority = 4096 direction = "Inbound" access = "Deny" protocol = "*" source_port_range = "*" destination_port_range = "*" source_address_prefix = "*" destination_address_prefix = "*" } tags = local.common_tags }
# App tier: only web tier can reach port 8080 resource "azurerm_network_security_group" "app" { name = "${var.project}-${var.environment}-app-nsg" location = azurerm_resource_group.spoke.location resource_group_name = azurerm_resource_group.spoke.name
security_rule { name = "AllowWebTier" priority = 100 direction = "Inbound" access = "Allow" protocol = "Tcp" source_port_range = "*" destination_port_range = "8080" source_address_prefix = "10.1.1.0/24" # web subnet destination_address_prefix = "*" } security_rule { name = "AllowAzureLoadBalancer" priority = 200 direction = "Inbound" access = "Allow" protocol = "*" source_port_range = "*" destination_port_range = "*" source_address_prefix = "AzureLoadBalancer" destination_address_prefix = "*" } security_rule { name = "DenyAllInbound" priority = 4096 direction = "Inbound" access = "Deny" protocol = "*" source_port_range = "*" destination_port_range = "*" source_address_prefix = "*" destination_address_prefix = "*" } tags = local.common_tags }
# Data tier: only app tier on PostgreSQL port resource "azurerm_network_security_group" "data" { name = "${var.project}-${var.environment}-data-nsg" location = azurerm_resource_group.spoke.location resource_group_name = azurerm_resource_group.spoke.name
security_rule { name = "AllowAppTierPostgreSQL" priority = 100 direction = "Inbound" access = "Allow" protocol = "Tcp" source_port_range = "*" destination_port_range = "5432" source_address_prefix = "10.1.2.0/24" # app subnet destination_address_prefix = "*" } security_rule { name = "DenyAllInbound" priority = 4096 direction = "Inbound" access = "Deny" protocol = "*" source_port_range = "*" destination_port_range = "*" source_address_prefix = "*" destination_address_prefix = "*" } tags = local.common_tags }

resource "azurerm_network_watcher_flow_log" "private" { name = "${var.project}-${var.environment}-private-nsg-flow" network_watcher_name = "NetworkWatcher_${var.location}" resource_group_name = "NetworkWatcherRG"
network_security_group_id = azurerm_network_security_group.private.id storage_account_id = azurerm_storage_account.logs.id enabled = true version = 2
retention_policy { enabled = true days = 30 }
traffic_analytics { enabled = true workspace_id = azurerm_log_analytics_workspace.main.workspace_id workspace_region = azurerm_log_analytics_workspace.main.location workspace_resource_id = azurerm_log_analytics_workspace.main.id interval_in_minutes = 10 }
tags = local.common_tags }
